INSERT INTO `MARKETPLACE_QUIZ_T` (`marketplace_quiz_id`, `marketplace_course_id`, `level_number`, `title`, `description`, `created_at`, `updated_at`) VALUES
(1, 1, 1, 'Addition', 'Add whole numbers together, from single digits up to hundreds.', '2026-06-29 10:09:07', '2026-06-29 10:09:07'),
(2, 1, 2, 'Subtraction', 'Take one number away from another and find the difference.', '2026-06-29 10:09:07', '2026-06-29 10:09:07'),
(3, 1, 3, 'Multiplication', 'Multiply numbers together using your times tables.', '2026-06-29 10:09:07', '2026-06-29 10:09:07'),
(4, 1, 4, 'Division', 'Split a number into equal parts and find how many fit.', '2026-06-29 10:09:07', '2026-06-29 10:09:07'),
(5, 1, 5, 'Boss Battle', 'The final test! A mix of addition, subtraction, multiplication and division, including order-of-operations.', '2026-06-29 10:09:07', '2026-06-29 10:09:07'),
(6, 2, 1, 'Variables & Data Types', 'Learn how to declare variables and the basic data types (int, float, str, bool).', '2026-06-29 10:48:08', '2026-06-29 10:48:08'),
(7, 2, 2, 'Strings', 'Indexing, slicing, common methods, and f-strings.', '2026-06-29 10:48:08', '2026-06-29 10:48:08'),
(8, 2, 3, 'Control Flow', 'Make decisions with if, elif, and else, plus comparison and logical operators.', '2026-06-29 10:48:08', '2026-06-29 10:48:08'),
(9, 2, 4, 'Loops', 'Repeat work with for and while loops, plus break and continue.', '2026-06-29 10:48:08', '2026-06-29 10:48:08'),
(10, 2, 5, 'Functions', 'Define reusable logic with def, parameters, arguments, and return.', '2026-06-29 10:48:08', '2026-06-29 10:48:08'),
(11, 2, 6, 'Boss Battle', 'The final challenge! A mix of variables, strings, control flow, loops and functions.', '2026-06-29 10:48:08', '2026-06-29 10:48:08');
INSERT INTO `POLICY_T` (`policy_id`, `title`, `content`, `version`, `effective_date`, `updated_at`, `updated_by`) VALUES
(7, '1. Terms of Service (The Rules)', 'Welcome to Implose.gg! By creating an account, you agree to follow our community guidelines to keep the platform safe and fun for everyone. Absolutely no cheating, hacking, or using unauthorized third-party software is allowed on the platform. Toxicity, harassment, and hate speech in any platform chats will result in an immediate account suspension. Players are also strictly responsible for keeping their own login credentials secure and must not share their accounts.', 'v1.0', '2026-06-01', '2026-06-15 23:24:00', 1),
(8, '2. Privacy Policy', 'We highly value your privacy and security. We only collect basic account data like your username, email address, and IP address for profile authentication and account recovery purposes. Your account password is encrypted immediately using secure backend hashing to safeguard your profile. Our platform will never sell your personal data, match history, or user profile information to any third-party advertisers.', 'v1.0', '2026-10-01', '2026-06-15 23:24:00', 1),
(9, '3. Community Guidelines', 'Implose.gg is a shared learning space, and we expect every user to treat others with respect. Bullying, discrimination, sharing inappropriate content, or spamming in chat rooms and quiz lobbies is strictly prohibited. Please keep conversations focused on learning and encourage your fellow students. Reports of misconduct will be reviewed by our moderation team, and repeat offenders may lose access to community features.', 'v1.0', '2026-06-15', '2026-06-15 23:24:00', 6),
(10, '4. Account Termination & Suspension', 'Accounts found violating our platform rules may be suspended or permanently banned without prior notice. Common reasons include cheating, harassing other users, or sharing account credentials. If you believe your account was suspended in error, you can appeal by contacting our support team through the Contact Us page. After account deletion, your personal data will be removed from our servers within thirty days.', 'v1.0', '2026-07-02', '2026-07-03 16:32:03', 1),
(11, '5. Intellectual Property & Learning Content', 'All courses, quizzes, learning materials, and platform design belong to Implose.gg and its content creators. Users may not copy, redistribute, or resell any platform content without written permission. When you submit user-generated content such as chat messages or feedback, you grant Implose.gg a non-exclusive license to display it within the platform. Please respect the original authors and sources when discussing study material.', 'v1.0', '2026-07-02', '2026-07-03 16:32:03', 1),
(12, '6. Age Eligibility', 'Implose.gg is designed for students aged thirteen and above. Users under the age of eighteen are encouraged to seek parental or guardian approval before creating an account. Schools and educators can contact us for classroom partnerships to bring Implose.gg to younger students in supervised environments. We reserve the right to remove any account we believe does not meet our age requirements.', 'v1.0', '2026-07-02', '2026-07-03 16:32:03', 1),
(13, '7. Changes to This Policy', 'We may update these policies from time to time to reflect improvements to the platform or new legal requirements. When we make significant changes, we will notify you via email or through an announcement on the platform. Your continued use of Implose.gg after such changes means you accept the updated terms. The date of the most recent update will always be shown at the top of this page.', 'v1.0', '2026-07-02', '2026-07-03 16:32:03', 1);
